    .wuxia-container::before {
      content: '';
      position: absolute;
      top: -60px;
      right: -60px;
      width: 220px;
      height: 220px;
      background: radial-gradient(circle, rgba(0,0,0,0.08) 0%, transparent 70%);
      border-radius: 50%;
      filter: blur(25px);
      z-index: 0;
      pointer-events: none;
