    .section-title {
      font-family: 'Ma Shan Zheng', cursive;
      font-size: 1.2em;
      text-align: center;
      margin-bottom: 10px;
      color: #5d4037;
      text-shadow: 1px 1px 0px rgba(255,255,255,0.5);
