        try {
          await navigator.clipboard.writeText(promptText);
          if (typeof toastr !== 'undefined') {
            toastr.success('天命已复制！请直接粘贴发送，开启旅程。', '穿越成功');
          }
        } catch (err) {
          console.error('Copy failed', err);
          if (typeof toastr !== 'undefined') {
            toastr.error('复制失败，请手动记录。', '天机屏蔽');
          }
